parameters.jsCode:
const title = $("맥락 수집").first().json.title;
const out = $("맥락 충분성 게이트").first().json.output || {};
const b = out.briefing || {};
const used = Array.isArray(out.context_used) ? out.context_used : [];
const lookup = $("담당자 Slack 조회").first().json;
const slackId = (lookup && lookup.user && lookup.user.id) ? lookup.user.id : null;
const mention = slackId ? ("<@" + slackId + ">") : "담당자";
const blocks = [
  { type: "section", text: { type: "mrkdwn", text: mention + " 님, 기획 검토 요청이에요.\n*📋 " + title + "*" } },
  { type: "divider" }
];
const parts = ["*🧭 제가 이해한 기획 의도*"];
if (b.summary) { parts.push("*목적*\n" + b.summary); }
if (b.scope) { parts.push("*대상*\n" + b.scope); }
const flows = Array.isArray(b.flows) ? b.flows.filter(Boolean) : [];
if (flows.length) { parts.push("*흐름*\n" + flows.map(function(f){ return "•  " + f; }).join("\n")); }
if (b.unclear) { parts.push("*확인 필요*\n" + b.unclear); }
if (parts.length === 1 && out.intent_briefing) { parts.push(out.intent_briefing); }
blocks.push({ type: "section", text: { type: "mrkdwn", text: parts.join("\n\n") } });
if (used.length) {
  blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: "📚 *참고한 지식*\n" + used.map(function(u){ return "•  " + u; }).join("\n") }] });
}
blocks.push({ type: "divider" });
blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: "👇 위 이해가 맞는지 확인하고 스레드에서 답변해 주세요. 다르면 정정해 주셔도 돼요." }] });
return [{ json: { body: { channel: "C0B9LE2FF36", text: mention + " 님, 기획 검토 요청", blocks: blocks } } }];

const out = $("맥락 충분성 게이트").first().json.output || {};
const qs = out.questions || [];
const roles = out.roles || [];
const pageId = $("맥락 수집").first().json.pageId;
const parent = $("부모 메시지 포스트").first().json;
const roleText = roles.length ? roles.join("·") : "관련 직무";
const intro = "📋 이 건은 *" + roleText + "* 관점으로 검토했어요. 검토 질문이 " + qs.length + "개 있어요. (관점이 다르면 이 스레드에 알려주세요)";
const guide = [
  "• *📝 답변하기* — 폼을 열어 질문에 답해요.",
  "• *🛑 보류* — 이 건을 멈춰요. 더 묻지 않을게요."
].join("\n");
const blocks = [
  { type: "section", text: { type: "mrkdwn", text: intro } },
  { type: "section", text: { type: "mrkdwn", text: guide } },
  { type: "actions", block_id: "prompt_actions", elements: [
    { type: "button", style: "primary", text: { type: "plain_text", text: "📝 답변하기", emoji: true }, action_id: "open_form", value: JSON.stringify({ pageId: pageId }) },
    { type: "button", style: "danger", text: { type: "plain_text", text: "🛑 보류", emoji: true }, action_id: "hold", value: JSON.stringify({ pageId: pageId }) }
  ] }
];
return [{ json: { body: { channel: parent.channel, thread_ts: parent.ts, text: "검토 질문", blocks: blocks } } }];

